    48→template <class Base> class FactoryRegistryProxyImpl : public FactoryRegistryProxy {
    49→public:
    50→  using FactoryRegistry = Envoy::Registry::FactoryRegistry<Base>;
    51→
    52→  std::vector<absl::string_view> registeredNames() const override {
    53→    return FactoryRegistry::registeredNames();
    54→  }
    55→
    56→  std::vector<absl::string_view> allRegisteredNames() const override {
    57→    return FactoryRegistry::registeredNames(true);
    58→  }
    59→
    60→  absl::optional<envoy::config::core::v3::BuildVersion>
    61→  getFactoryVersion(absl::string_view name) const override {
    62→    return FactoryRegistry::getFactoryVersion(name);
    63→  }
    64→
    65→  bool disableFactory(absl::string_view name) override {
    66→    return FactoryRegistry::disableFactory(name);
    67→  }
    68→
    69→  bool isFactoryDisabled(absl::string_view name) const override {
    70→    return FactoryRegistry::isFactoryDisabled(name);
    71→  }
    72→
    73→  absl::flat_hash_map<std::string, std::vector<std::string>> registeredTypes() const override {
    74→    return FactoryRegistry::registeredTypes();
    75→  }
    76→
    77→  absl::string_view canonicalFactoryName(absl::string_view name) const override {
    78→    return FactoryRegistry::canonicalFactoryName(name);
    79→  }
    80→};
